AstrumParser::AstrumParser(TokenStream* input)
    : AstrumParser(input, antlr4::atn::ParserATNSimulatorOptions()) {}

AstrumParser::AstrumParser(TokenStream* input,
                           const antlr4::atn::ParserATNSimulatorOptions& options)
    : Parser(input) {
	AstrumParser::initialize();
	_interpreter = new atn::ParserATNSimulator(
	    this, *astrumparserParserStaticData->atn, astrumparserParserStaticData->decisionToDFA,
	    astrumparserParserStaticData->sharedContextCache, options);
}

AstrumParser::~AstrumParser() { delete _interpreter; }

const atn::ATN& AstrumParser::getATN() const { return *astrumparserParserStaticData->atn; }

std::string AstrumParser::getGrammarFileName() const { return "AstrumParser.g4"; }

const std::vector<std::string>& AstrumParser::getRuleNames() const {
	return astrumparserParserStaticData->ruleNames;
}

const dfa::Vocabulary& AstrumParser::getVocabulary() const {
	return astrumparserParserStaticData->vocabulary;
}

antlr4::atn::SerializedATNView AstrumParser::getSerializedATN() const {
	return astrumparserParserStaticData->serializedATN;
}

//----------------- ModuleContext ------------------------------------------------------------------

AstrumParser::ModuleContext::ModuleContext(ParserRuleContext* parent, size_t invokingState)
    : ParserRuleContext(parent, invokingState) {}

AstrumParser::DeclarationSeqContext* AstrumParser::ModuleContext::declarationSeq() {
	return getRuleContext<AstrumParser::DeclarationSeqContext>(0);
}

